int main(){string s;cin>>s;vector<long long>nums;vector<char>ops;long long cur=0;bool has=false;for(char c:s){if(isdigit(c)){cur=cur*10+(c-'0');has=true;}else{nums.push_back(cur);cur=0;has=false;ops.push_back(c);}}nums.push_back(cur);long long ans=nums[0];bool minus=false;for(int i=0;i<(int)ops.size();i++){if(ops[i]=='-')minus=true;if(minus)ans-=nums[i+1];else ans+=nums[i+1];}cout<<ans<<"\n";}
